import { PublicKey } from "../crypto";
import { BincodeWriter } from "../serialization/bincode";
import type { Instruction } from "../transaction/types";
import { RISCV_LOADER_PROGRAM_ID } from "./constants";

/**
 * RISC-V loader instruction variant indices.
 * Must match `RiscVLoaderInstruction` enum order in Rust (bincode u32 encoding).
 */
export enum RiscVLoaderInstruction {
  Write = 0,
  Copy = 1,
  SetProgramLength = 2,
  Deploy = 3,
  Retract = 4,
  TransferAuthority = 5,
  Finalize = 6,
}

const LOADER_PROGRAM_ID = PublicKey.fromString(RISCV_LOADER_PROGRAM_ID);

/**
 * Create a Write instruction to write bytecode into an undeployed program account.
 * Accounts: [program (writable), authority (signer)]
 */
export function writeInstruction(
  programAddress: PublicKey,
  authority: PublicKey,
  offset: number,
  bytes: Uint8Array,
): Instruction {
  const writer = new BincodeWriter(4 + 4 + 8 + bytes.length);
  writer.writeVariant(RiscVLoaderInstruction.Write);
  writer.writeU32(offset);
  writer.writeVecBytes(bytes);

  return {
    programId: LOADER_PROGRAM_ID,
    accounts: [
      { pubkey: programAddress, isSigner: false, isWritable: true },
      { pubkey: authority, isSigner: true, isWritable: false },
    ],
    data: writer.toBytes(),
  };
}

/**
 * Create a SetProgramLength instruction to resize a program account.
 * Accounts: [program (writable), authority (signer), recipient (writable)]
 */
export function setProgramLengthInstruction(
  programAddress: PublicKey,
  authority: PublicKey,
  newSize: number,
  recipientAddress: PublicKey,
): Instruction {
  const writer = new BincodeWriter(8);
  writer.writeVariant(RiscVLoaderInstruction.SetProgramLength);
  writer.writeU32(newSize);

  return {
    programId: LOADER_PROGRAM_ID,
    accounts: [
      { pubkey: programAddress, isSigner: false, isWritable: true },
      { pubkey: authority, isSigner: true, isWritable: false },
      { pubkey: recipientAddress, isSigner: false, isWritable: true },
    ],
    data: writer.toBytes(),
  };
}

/**
 * Create a Deploy instruction to make a program executable.
 * Accounts: [program (writable), authority (signer)]
 */
export function deployInstruction(programAddress: PublicKey, authority: PublicKey): Instruction {
  const writer = new BincodeWriter(4);
  writer.writeVariant(RiscVLoaderInstruction.Deploy);

  return {
    programId: LOADER_PROGRAM_ID,
    accounts: [
      { pubkey: programAddress, isSigner: false, isWritable: true },
      { pubkey: authority, isSigner: true, isWritable: false },
    ],
    data: writer.toBytes(),
  };
}

/**
 * Create a Retract instruction to undo deployment (enters maintenance mode).
 * Accounts: [program (writable), authority (signer)]
 */
export function retractInstruction(programAddress: PublicKey, authority: PublicKey): Instruction {
  const writer = new BincodeWriter(4);
  writer.writeVariant(RiscVLoaderInstruction.Retract);

  return {
    programId: LOADER_PROGRAM_ID,
    accounts: [
      { pubkey: programAddress, isSigner: false, isWritable: true },
      { pubkey: authority, isSigner: true, isWritable: false },
    ],
    data: writer.toBytes(),
  };
}
