/**
 * Fluent API for building transactions.
 * Returns Transaction directly (not Message).
 */

import type { PublicKey } from "../crypto";
import { AccountMetaTable } from "./account-meta-table";
import { TransactionError, TransactionErrorCode } from "./errors";
import { Message } from "./message";
import { Transaction } from "./transaction";
import type { CompiledInstruction, Instruction } from "./types";

/**
 * Builder for creating transactions with a fluent API.
 *
 * Provides an intuitive interface for constructing transactions.
 * Call build() to get an unsigned Transaction ready for signing.
 *
 * @example
 * ```typescript
 * // Simple transfer
 * const tx = TransactionBuilder.create()
 *   .setPayer(payer)
 *   .setValidFrom(validFrom)
 *   .addInstruction(transfer(from, to, 1_000_000n))
 *   .build();
 *
 * const signedTx = tx.sign(keypair);
 * await client.transaction.sendTransaction(signedTx.serialize());
 * ```
 *
 * @example
 * ```typescript
 * // Multi-instruction transaction
 * const tx = TransactionBuilder.create()
 *   .setPayer(payer)
 *   .setValidFrom(validFrom)
 *   .addInstruction(transfer(from, to, 1_000_000n))
 *   .addInstruction(memoInstruction("Payment for invoice #123"))
 *   .build();
 * ```
 */
export class TransactionBuilder {
	private payer?: PublicKey;
    private validFrom?: bigint;
    private configHashPrefix?: bigint;
    private occ = false;
	private readonly instructions: Instruction[] = [];

	private constructor() {}

	/**
	 * Create a new transaction builder.
	 */
	static create(): TransactionBuilder {
		return new TransactionBuilder();
	}

	/**
	 * Set the fee payer for this transaction.
	 *
	 * The payer will be the first account and must sign the transaction.
	 * The payer pays for transaction fees.
	 *
	 * @param payer - Public key of the fee payer
	 */
	setPayer(payer: PublicKey): this {
		this.payer = payer;
		return this;
	}

    /**
     * Set the Transaction valid from.
     *
     * This is the time the transaction is valid from, in milliseconds since Unix epoch.
     * It can be used for additional replay protection or auditing.
     *
     * @param validFrom - Transaction valid from in milliseconds since Unix epoch
     */
    setValidFrom(validFrom: bigint): this {
        this.validFrom = validFrom;
        return this;
    }

    /**
     * Set the config hash prefix for replay protection.
     *
     * This is the first 64 bits of the config hash, used to ensure
     * transactions cannot be replayed on different chains.
     *
     * @param configHashPrefix - config hash prefix as a u64
     */
    setConfigHashPrefix(configHashPrefix: bigint): this {
        this.configHashPrefix = configHashPrefix;
        return this;
    }

    /**
     * Enable OCC (optimistic concurrency control) scheduling for this transaction.
     *
     * @param occ - Whether to use OCC scheduling (default: false)
     */
    setOcc(occ: boolean): this {
        this.occ = occ;
        return this;
    }

	/**
	 * Add an instruction to the transaction.
	 *
	 * @param instruction - Instruction to add
	 */
	addInstruction(instruction: Instruction): this {
		this.instructions.push(instruction);
		return this;
	}

	/**
	 * Add multiple instructions at once.
	 *
	 * @param instructions - Array of instructions to add
	 */
	addInstructions(instructions: readonly Instruction[]): this {
		this.instructions.push(...instructions);
		return this;
	}

	/**
	 * Build the transaction (unsigned).
	 *
	 * Returns an unsigned Transaction that's ready to be signed.
	 *
	 * @returns Unsigned Transaction
	 * @throws {TransactionError} If payer, valid_from, or instructions are missing
	 *
	 * @example
	 * ```typescript
	 * const tx = builder.build();
	 * const signedTx = tx.sign(keypair);
	 * ```
	 */
	build(): Transaction {
		// Validate required fields
		if (!this.payer) {
			throw new TransactionError(
				TransactionErrorCode.INVALID_ACCOUNT_META,
				"Transaction must have a fee payer. Use setPayer() to set the fee payer.",
			);
		}

        if (!this.validFrom) {
            throw new TransactionError(
                TransactionErrorCode.INVALID_MESSAGE_FORMAT,
                "Transaction must have a valid from. Use setValidFrom() to set the valid from.",
            );
        }

        if (this.configHashPrefix === undefined) {
            throw new TransactionError(
                TransactionErrorCode.INVALID_MESSAGE_FORMAT,
                "Transaction must have a config hash prefix. Use setConfigHashPrefix() to set the config hash prefix.",
            );
        }

		if (this.instructions.length === 0) {
			throw TransactionError.noInstructions();
		}

		// Build account meta table
		const accountTable = new AccountMetaTable();

		// Pin payer at index 0 (signer + writable)
		accountTable.setFeePayer(this.payer);

		// Add all accounts from instructions
		for (const instruction of this.instructions) {
			accountTable.addAll(instruction.accounts);

			// Add program ID as readonly non-signer
			accountTable.add({
				pubkey: instruction.programId,
				isSigner: false,
				isWritable: false,
			});
		}

		// Get sorted accounts and header
		const accountKeys = accountTable.getPublicKeys();
		const header = accountTable.getHeader();

		// Compile instructions (convert pubkeys to indices)
		const compiledInstructions = this.instructions.map((instruction) => {
			const programIdIndex = accountTable.getIndex(instruction.programId);
			if (programIdIndex === -1) {
				throw new TransactionError(
					TransactionErrorCode.INVALID_INSTRUCTION,
					`Program ID ${instruction.programId.toString()} not found in account table`,
				);
			}

			const accountKeyIndexes = instruction.accounts.map((meta) => {
				const index = accountTable.getIndex(meta.pubkey);
				if (index === -1) {
					throw new TransactionError(
						TransactionErrorCode.INVALID_INSTRUCTION,
						`Account ${meta.pubkey.toString()} not found in account table`,
					);
				}
				return index;
			});

			const compiled: CompiledInstruction = {
				programIdIndex,
				accountKeyIndexes: Object.freeze(accountKeyIndexes),
				data: instruction.data,
			};

			return compiled;
		});

		// Create message
		const message = new Message(
			header,
			accountKeys,
            this.validFrom,
            this.configHashPrefix,
            this.occ,
			compiledInstructions,
		);

		// Return unsigned transaction
		return Transaction.fromMessage(message);
	}
}
