import {
	URL_DEVNET,
	URL_LOCALNET,
	URL_MAINNET,
	URL_TESTNET,
} from "./constants";

/**
 * Converts bytes to base64 string.
 *
 * Works in both browser and Node.js environments.
 */
export function toBase64(bytes: Uint8Array): string {
	// Browser environment
	if (typeof btoa !== "undefined") {
		// For large arrays, chunk to avoid call stack size exceeded
		const chunkSize = 8192;
		let result = "";

		for (let i = 0; i < bytes.length; i += chunkSize) {
			const chunk = bytes.slice(i, i + chunkSize);
			result += String.fromCharCode(...chunk);
		}

		return btoa(result);
	}

	// Node.js environment
	if (typeof Buffer !== "undefined") {
		return Buffer.from(bytes).toString("base64");
	}

	throw new Error("No base64 encoding available in this environment");
}

/**
 * Converts base64 string to bytes.
 *
 * Works in both browser and Node.js environments.
 */
export function fromBase64(base64: string): Uint8Array {
	// Browser environment
	if (typeof atob !== "undefined") {
		const binary = atob(base64);
		const bytes = new Uint8Array(binary.length);
		for (let i = 0; i < binary.length; i++) {
			bytes[i] = binary.charCodeAt(i);
		}
		return bytes;
	}

	// Node.js environment
	if (typeof Buffer !== "undefined") {
		return new Uint8Array(Buffer.from(base64, "base64"));
	}

	throw new Error("No base64 decoding available in this environment");
}

/**
 * Sleeps for the specified duration.
 *
 * @param ms - Milliseconds to sleep
 */
export function sleep(ms: number): Promise<void> {
	return new Promise((resolve) => setTimeout(resolve, ms));
}

/**
 * Calculates exponential backoff delay with jitter.
 *
 * @param attempt - Current retry attempt (0-indexed)
 * @param baseMs - Base delay in milliseconds
 * @param maxMs - Maximum delay in milliseconds
 * @returns Calculated delay with 30% random jitter
 */
export function calculateBackoff(
	attempt: number,
	baseMs = 1000,
	maxMs = 30000,
): number {
	const exponentialDelay = baseMs * 2 ** attempt;
	const jitter = Math.random() * 0.3 * exponentialDelay; // 30% jitter
	return Math.min(exponentialDelay + jitter, maxMs);
}

/**
 * Returns the devnet RPC URL.
 */
export function getDevnetUrl(): string {
	return URL_DEVNET;
}

/**
 * Returns the testnet RPC URL.
 */
export function getTestnetUrl(): string {
	return URL_TESTNET;
}

/**
 * Returns the mainnet RPC URL.
 */
export function getMainnetUrl(): string {
	return URL_MAINNET;
}

/**
 * Returns the localnet RPC URL.
 */
export function getLocalnetUrl(): string {
	return URL_LOCALNET;
}
