import { PublicKey } from "../crypto";
import { TransactionError, TransactionErrorCode } from "./errors";
import type { CompiledInstruction, MessageHeader } from "./types";

/**
 * An unsigned transaction message ready to be signed.
 *
 * This is the data that gets signed by transaction signers.
 * It's immutable to prevent accidental modification after creation.
 *
 * @example
 * ```typescript
 * const message = MessageBuilder.create()
 *   .setPayer(payer)
 *   .setValidFrom(validFrom)
 *   .addInstruction(transferInstruction)
 *   .build();
 *
 * // Serialize for signing
 * const messageBytes = message.serialize();
 * ```
 */
export class Message {
	/** Message header with signature requirements */
	public readonly header: MessageHeader;

	/** All account public keys referenced in the transaction */
	public readonly accountKeys: readonly PublicKey[];

	/** Transaction valid from (milliseconds since Unix epoch) */
	validFrom?: bigint;

	/** Config hash prefix for replay protection across chains */
	public readonly configHashPrefix: bigint;

	/** Whether the transaction should use OCC (optimistic concurrency control) scheduling */
	public readonly occ: boolean;

	/** Compiled instructions with account indices */
	public readonly instructions: readonly CompiledInstruction[];

	/** Cached serialized bytes */
	private serializedCache?: Uint8Array;

	constructor(
		header: MessageHeader,
		accountKeys: readonly PublicKey[],
		validFrom: bigint,
		configHashPrefix: bigint,
		occ: boolean,
		instructions: readonly CompiledInstruction[],
	) {
		this.header = Object.freeze({ ...header });
		this.accountKeys = Object.freeze([...accountKeys]);
		this.validFrom = validFrom;
		this.configHashPrefix = configHashPrefix;
		this.occ = occ;
		this.instructions = Object.freeze(
			instructions.map((ix) => Object.freeze({ ...ix })),
		);
	}

	/**
	 * Serialize message to bytes for signing.
	 * Result is cached for performance.
	 */
	serialize(): Uint8Array {
		if (!this.serializedCache) {
			this.serializedCache = this.serializeInternal();
		}
		return new Uint8Array(this.serializedCache); // Return copy
	}

	/**
	 * Deserialize a message from wire format.
	 *
	 * @param data - Serialized message bytes
	 * @returns Deserialized Message
	 */
	static deserialize(data: Uint8Array): Message {
		if (data.length < 3) {
			throw new TransactionError(
				TransactionErrorCode.INSUFFICIENT_DATA,
				"Insufficient data for message header",
			);
		}

		let cursor = 0;

		// Deserialize header (3 bytes)
		const header: MessageHeader = {
			numRequiredSignatures: data[cursor++],
			numReadonlySignedAccounts: data[cursor++],
			numReadonlyUnsignedAccounts: data[cursor++],
		};

		// Deserialize account keys with compact-u16 length prefix
		const [accountKeysLength, newCursor1] = deserializeCompactU16(data, cursor);
		cursor = newCursor1;

		const accountKeys: PublicKey[] = [];
		for (let i = 0; i < accountKeysLength; i++) {
			if (data.length < cursor + 32) {
				throw new TransactionError(
					TransactionErrorCode.INSUFFICIENT_DATA,
					`Insufficient data for account key ${i}`,
				);
			}
			const keyBytes = data.slice(cursor, cursor + 32);
			accountKeys.push(PublicKey.fromBytes(keyBytes));
			cursor += 32;
		}

		// Deserialize recent valid from (8 bytes)
		if (data.length < cursor + 8) {
			throw new TransactionError(
				TransactionErrorCode.INSUFFICIENT_DATA,
				"Insufficient data for validFrom",
			);
		}
		const validFromBytes = data.slice(cursor, cursor + 8);
		const validFrom = BigInt.asUintN(
			64,
			new DataView(validFromBytes.buffer).getBigUint64(0, true),
		);
		cursor += 8;

		// Deserialize config hash prefix (8 bytes)
		if (data.length < cursor + 8) {
			throw new TransactionError(
				TransactionErrorCode.INSUFFICIENT_DATA,
				"Insufficient data for configHashPrefix",
			);
		}
		const configHashPrefixBytes = data.slice(cursor, cursor + 8);
		const configHashPrefix = BigInt.asUintN(
			64,
			new DataView(configHashPrefixBytes.buffer).getBigUint64(0, true),
		);
		cursor += 8;

		// Deserialize occ flag (1 byte)
		if (data.length < cursor + 1) {
			throw new TransactionError(
				TransactionErrorCode.INSUFFICIENT_DATA,
				"Insufficient data for occ flag",
			);
		}
		const occ = data[cursor++] !== 0;

		// Deserialize instructions with compact-u16 length prefix
		const [instructionsLength, newCursor2] = deserializeCompactU16(
			data,
			cursor,
		);
		cursor = newCursor2;

		const instructions: CompiledInstruction[] = [];
		for (let i = 0; i < instructionsLength; i++) {
			// Read program ID index
			if (data.length < cursor + 1) {
				throw new TransactionError(
					TransactionErrorCode.INSUFFICIENT_DATA,
					`Insufficient data for instruction ${i} program index`,
				);
			}
			const programIdIndex = data[cursor++];

			// Read account key indexes array
			const [accountIndexesLength, newCursor3] = deserializeCompactU16(
				data,
				cursor,
			);
			cursor = newCursor3;

			const accountKeyIndexes: number[] = [];
			for (let j = 0; j < accountIndexesLength; j++) {
				if (data.length < cursor + 1) {
					throw new TransactionError(
						TransactionErrorCode.INSUFFICIENT_DATA,
						`Insufficient data for instruction ${i} account index ${j}`,
					);
				}
				accountKeyIndexes.push(data[cursor++]);
			}

			// Read instruction data array
			const [dataLength, newCursor4] = deserializeCompactU16(data, cursor);
			cursor = newCursor4;

			if (data.length < cursor + dataLength) {
				throw new TransactionError(
					TransactionErrorCode.INSUFFICIENT_DATA,
					`Insufficient data for instruction ${i} data`,
				);
			}
			const instructionData = data.slice(cursor, cursor + dataLength);
			cursor += dataLength;

			instructions.push({
				programIdIndex,
				accountKeyIndexes: Object.freeze(accountKeyIndexes),
				data: instructionData,
			});
		}

		return new Message(header, accountKeys, validFrom, configHashPrefix, occ, instructions);
	}

	private serializeInternal(): Uint8Array {
		const buffer: number[] = [];

		// Serialize header (3 bytes)
		buffer.push(this.header.numRequiredSignatures);
		buffer.push(this.header.numReadonlySignedAccounts);
		buffer.push(this.header.numReadonlyUnsignedAccounts);

		// Serialize account keys with compact-u16 length prefix
		this.serializeCompactArray(buffer, this.accountKeys, (buf, key) => {
			buf.push(...key.toBytes());
		});

		// Serialize recent valid from (8 bytes, little-endian to match Rust's bincode)
		const validFromBuffer = new ArrayBuffer(8);
		new DataView(validFromBuffer).setBigUint64(
			0,
			this.validFrom ?? BigInt(0),
			true,
		);
		buffer.push(...new Uint8Array(validFromBuffer));

		// Serialize config hash prefix (8 bytes, little-endian)
		const configHashPrefixBuffer = new ArrayBuffer(8);
		new DataView(configHashPrefixBuffer).setBigUint64(
			0,
			this.configHashPrefix,
			true,
		);
		buffer.push(...new Uint8Array(configHashPrefixBuffer));

		// Serialize occ flag (1 byte, bincode bool)
		buffer.push(this.occ ? 1 : 0);

		// Serialize instructions with compact-u16 length prefix
		this.serializeCompactArray(buffer, this.instructions, (buf, ix) => {
			// Program ID index (1 byte)
			buf.push(ix.programIdIndex);

			// Account indexes array
			this.serializeCompactArray(buf, ix.accountKeyIndexes, (b, idx) => {
				b.push(idx);
			});

			// Instruction data array
			this.serializeCompactArray(buf, Array.from(ix.data), (b, byte) => {
				b.push(byte);
			});
		});

		return new Uint8Array(buffer);
	}

	private serializeCompactArray<T>(
		buffer: number[],
		items: readonly T[],
		serializeItem: (buf: number[], item: T) => void,
	): void {
		// Serialize length as compact-u16
		this.serializeCompactU16(buffer, items.length);

		// Serialize each item
		for (const item of items) {
			serializeItem(buffer, item);
		}
	}

	private serializeCompactU16(buffer: number[], value: number): void {
		if (value < 0 || value > 0xffff) {
			throw new Error(`Value out of range for compact-u16: ${value}`);
		}

		// Single byte (0-127)
		if (value <= 0x7f) {
			buffer.push(value);
			return;
		}

		// Two bytes (128-16383)
		if (value <= 0x3fff) {
			buffer.push((value & 0x7f) | 0x80);
			buffer.push((value >> 7) & 0x7f);
			return;
		}

		// Three bytes (16384-65535)
		buffer.push((value & 0x7f) | 0x80);
		buffer.push(((value >> 7) & 0x7f) | 0x80);
		buffer.push((value >> 14) & 0xff);
	}

	/**
	 * Get all signers required for this message.
	 */
	getSigners(): readonly PublicKey[] {
		return this.accountKeys.slice(0, this.header.numRequiredSignatures);
	}

	/**
	 * Check if a public key is a required signer.
	 */
	isSignerRequired(pubkey: PublicKey): boolean {
		return this.getSigners().some((signer) => signer.equals(pubkey));
	}

	/**
	 * Get the index of a signer in the signers array.
	 * Returns -1 if not a signer.
	 */
	getSignerIndex(pubkey: PublicKey): number {
		return this.getSigners().findIndex((signer) => signer.equals(pubkey));
	}
}

function deserializeCompactU16(
	data: Uint8Array,
	currentCursor: number,
): [number, number] {
	let cursor = currentCursor;
	if (cursor >= data.length) {
		throw new TransactionError(
			TransactionErrorCode.INSUFFICIENT_DATA,
			"Insufficient data for compact-u16",
		);
	}

	const firstByte = data[cursor++];

	// Single byte encoding (0-127)
	if ((firstByte & 0x80) === 0) {
		return [firstByte, cursor];
	}

	// Multi-byte encoding
	if (cursor >= data.length) {
		throw new TransactionError(
			TransactionErrorCode.INSUFFICIENT_DATA,
			"Incomplete compact-u16 encoding",
		);
	}

	const secondByte = data[cursor++];

	// Two-byte encoding (128-16383)
	if ((secondByte & 0x80) === 0) {
		return [(firstByte & 0x7f) | (secondByte << 7), cursor];
	}

	// Three-byte encoding (16384-65535)
	if (cursor >= data.length) {
		throw new TransactionError(
			TransactionErrorCode.INSUFFICIENT_DATA,
			"Incomplete compact-u16 encoding",
		);
	}

	const thirdByte = data[cursor++];
	const value =
		(firstByte & 0x7f) | ((secondByte & 0x7f) << 7) | (thirdByte << 14);

	return [value, cursor];
}
