/**
 * Low-level HTTP transport with retry logic and timeout handling.
 *
 * Provides robust network communication with automatic retry,
 * exponential backoff, and proper error handling.
 */
import { calculateBackoff, sleep } from "../utils";
import { RpcError, RpcErrorCode } from "./errors";

export interface HttpTransportConfig {
	/** Request timeout in milliseconds */
	timeout?: number;
	/** Maximum number of retry attempts */
	maxRetries?: number;
	/** Base delay for exponential backoff (ms) */
	retryBaseDelay?: number;
	/** Maximum retry delay (ms) */
	retryMaxDelay?: number;
	/** Custom headers to include in requests */
	headers?: Record<string, string>;
}

interface RequestOptions {
	method: string;
	headers: Record<string, string>;
	body: string;
	signal?: AbortSignal;
}

const DEFAULT_CONFIG: Required<HttpTransportConfig> = {
	timeout: 30000, // 30 seconds
	maxRetries: 3,
	retryBaseDelay: 1000, // 1 second
	retryMaxDelay: 30000, // 30 seconds
	headers: {},
};

/**
 * HTTP transport with built-in retry logic and timeout handling.
 *
 * Features:
 * - Automatic retries with exponential backoff
 * - Request timeouts using AbortController
 * - Network error recovery
 * - Rate limit handling
 * - Proper HTTP status code handling
 */
export class HttpTransport {
	private readonly url: string;
	private readonly config: Required<HttpTransportConfig>;

	constructor(url: string, config: HttpTransportConfig = {}) {
		this.url = url;
		this.config = { ...DEFAULT_CONFIG, ...config };
	}

	/**
	 * Makes an HTTP request with automatic retry logic.
	 *
	 * Retries are attempted for network errors and server errors (5xx).
	 * Uses exponential backoff between retry attempts.
	 */
	async request(
		body: string,
		requestDetails: Record<string, unknown> = {},
	): Promise<unknown> {
		let lastError: Error | undefined;

		for (let attempt = 0; attempt <= this.config.maxRetries; attempt++) {
			try {
				return await this.makeRequest(body, requestDetails, attempt);
			} catch (error) {
				lastError = error as Error;

				// Don't retry if it's not a retryable error
				if (error instanceof RpcError && !error.retryable) {
					throw error;
				}

				// Don't retry on the last attempt
				if (attempt === this.config.maxRetries) {
					throw error;
				}

				// Calculate backoff delay
				const delay = calculateBackoff(
					attempt,
					this.config.retryBaseDelay,
					this.config.retryMaxDelay,
				);

				// Wait before retrying
				await sleep(delay);
			}
		}

		// Should never reach here, but TypeScript doesn't know that
		throw lastError;
	}

	/**
	 * Make a single HTTP request with timeout
	 */
	private async makeRequest(
		body: string,
		requestDetails: Record<string, unknown>,
		attempt: number,
	): Promise<unknown> {
		const controller = new AbortController();
		const timeoutId = setTimeout(() => controller.abort(), this.config.timeout);

		try {
			const options: RequestOptions = {
				method: "POST",
				headers: {
					"Content-Type": "application/json",
					...this.config.headers,
				},
				body,
				signal: controller.signal,
			};

			const response = await fetch(this.url, options);

			// Handle HTTP errors
			if (!response.ok) {
				throw await this.handleHttpError(response, requestDetails, attempt);
			}

			// Parse JSON response
			const data = await response.json();
			return data;
		} catch (error) {
			// Handle timeout
			if (error instanceof Error && error.name === "AbortError") {
				throw RpcError.requestTimeout(this.config.timeout, {
					...requestDetails,
					url: this.url,
					attempts: attempt + 1,
				});
			}

			// Handle network errors
			if (error instanceof TypeError) {
				throw RpcError.networkError(error.message, {
					...requestDetails,
					url: this.url,
					attempts: attempt + 1,
					cause: error.message,
				});
			}

			// Re-throw RpcError
			if (error instanceof RpcError) {
				throw error;
			}

			// Unknown error
			throw RpcError.networkError("Unknown network error", {
				...requestDetails,
				url: this.url,
				attempts: attempt + 1,
				cause: error instanceof Error ? error.message : String(error),
			});
		} finally {
			clearTimeout(timeoutId);
		}
	}

	/**
	 * Handle HTTP error responses.
	 *
	 * Parses the response body to extract JSON-RPC error details when available,
	 * regardless of HTTP status code. Falls back to HTTP status-based error handling.
	 */
	private async handleHttpError(
		response: Response,
		requestDetails: Record<string, unknown>,
		attempt: number,
	): Promise<RpcError> {
		const status = response.status;
		const isRetryable = status >= 500 || status === 429;
		const baseDetails = {
			...requestDetails,
			httpStatus: status,
			url: this.url,
			attempts: attempt + 1,
		};

		// Try to parse response body for error details
		const { message, rpcCode, errorData } = await this.parseErrorResponse(
			response,
			status,
		);

		// Rate limiting gets special handling
		if (status === 429) {
			return RpcError.rateLimitExceeded({
				...baseDetails,
				serverError: errorData,
			});
		}

		// If we have a JSON-RPC error code, use proper error mapping
		if (rpcCode !== undefined) {
			return RpcError.fromRpcCode(rpcCode, message, {
				...baseDetails,
				serverError: errorData,
			});
		}

		// Server errors (5xx) are retryable network errors
		if (status >= 500) {
			return RpcError.networkError(message, {
				...baseDetails,
				serverError: errorData,
			});
		}

		// Client errors (4xx) are not retryable
		return new RpcError(RpcErrorCode.NETWORK_ERROR, message, baseDetails, isRetryable);
	}

	/**
	 * Parse error response body to extract message and RPC error code.
	 *
	 * Handles multiple formats:
	 * - JSON-RPC error: { error: { code, message, data? } }
	 * - Simple JSON: { message: "..." }
	 * - Non-JSON responses
	 */
	private async parseErrorResponse(
		response: Response,
		status: number,
	): Promise<{ message: string; rpcCode?: number; errorData?: unknown }> {
		let message = `HTTP ${status}: ${response.statusText}`;
		let rpcCode: number | undefined;
		let errorData: unknown;

		try {
			errorData = await response.json();

			if (errorData && typeof errorData === "object") {
				const data = errorData as Record<string, unknown>;

				// Check for JSON-RPC error format: { error: { code, message } }
				if (
					data.error &&
					typeof data.error === "object" &&
					"message" in data.error
				) {
					const rpcError = data.error as Record<string, unknown>;
					message = String(rpcError.message);
					rpcCode =
						typeof rpcError.code === "number" ? rpcError.code : undefined;
				} else if ("message" in data) {
					// Fallback to top-level message
					message = String(data.message);
				}
			}
		} catch {
			// Response might not be JSON, keep default message
		}

		return { message, rpcCode, errorData };
	}

	/**
	 * Returns the configured RPC endpoint URL.
	 */
	getUrl(): string {
		return this.url;
	}
}
