import { RialoError, RialoErrorType } from "../error.js";

const U32_MAX = 0xFFFFFFFF;

/**
 * Validates that a keypair index is a valid WIT u32 value.
 * Rejects negative, fractional, NaN, and values above 0xFFFFFFFF.
 */
export function validateKeypairIndex(index: number): void {
	if (!Number.isInteger(index) || index < 0 || index > U32_MAX) {
		throw new RialoError(
			RialoErrorType.INVALID_INPUT,
			`Invalid keypair index: ${index}. Must be a non-negative integer <= ${U32_MAX}.`,
		);
	}
}
