/**
 * Bincode deserialization reader
 *
 * Matches Rust's bincode crate with default configuration:
 * - Little-endian byte order
 * - Fixed-size integer encoding (no varint)
 * - u64 length prefixes for dynamic collections
 * - u32 enum variant indices
 */
export class BincodeReader {
	private view: DataView;
	private offset: number;
	private bytes: Uint8Array;

	constructor(data: Uint8Array) {
		this.bytes = data;
		this.view = new DataView(data.buffer, data.byteOffset, data.byteLength);
		this.offset = 0;
	}

	// ========== Position Management ==========

	getOffset(): number {
		return this.offset;
	}

	remaining(): number {
		return this.bytes.length - this.offset;
	}

	isExhausted(): boolean {
		return this.offset >= this.bytes.length;
	}

	skip(bytes: number): this {
		this.ensureAvailable(bytes);
		this.offset += bytes;
		return this;
	}

	/**
	 * Peek at bytes without advancing the offset
	 */
	peek(length: number): Uint8Array {
		this.ensureAvailable(length);
		return this.bytes.slice(this.offset, this.offset + length);
	}

	/**
	 * Reset reader to beginning
	 */
	reset(): this {
		this.offset = 0;
		return this;
	}

	/**
	 * Seek to specific offset
	 */
	seek(offset: number): this {
		if (offset < 0 || offset > this.bytes.length) {
			throw new Error(
				`Invalid seek offset: ${offset}, buffer length: ${this.bytes.length}`,
			);
		}
		this.offset = offset;
		return this;
	}

	// ========== Primitive Types ==========

	readU8(): number {
		this.ensureAvailable(1);
		const value = this.view.getUint8(this.offset);
		this.offset += 1;
		return value;
	}

	readU16(): number {
		this.ensureAvailable(2);
		const value = this.view.getUint16(this.offset, true);
		this.offset += 2;
		return value;
	}

	readU32(): number {
		this.ensureAvailable(4);
		const value = this.view.getUint32(this.offset, true);
		this.offset += 4;
		return value;
	}

	readU64(): bigint {
		this.ensureAvailable(8);
		const low = this.view.getUint32(this.offset, true);
		const high = this.view.getUint32(this.offset + 4, true);
		this.offset += 8;
		return BigInt(low) | (BigInt(high) << 32n);
	}

	readU128(): bigint {
		this.ensureAvailable(16);
		const low = this.readU64();
		const high = this.readU64();
		return low | (high << 64n);
	}

	readI8(): number {
		this.ensureAvailable(1);
		const value = this.view.getInt8(this.offset);
		this.offset += 1;
		return value;
	}

	readI16(): number {
		this.ensureAvailable(2);
		const value = this.view.getInt16(this.offset, true);
		this.offset += 2;
		return value;
	}

	readI32(): number {
		this.ensureAvailable(4);
		const value = this.view.getInt32(this.offset, true);
		this.offset += 4;
		return value;
	}

	readI64(): bigint {
		this.ensureAvailable(8);
		const low = this.view.getUint32(this.offset, true);
		const high = this.view.getInt32(this.offset + 4, true);
		this.offset += 8;
		// Use BigInt arithmetic to properly handle sign extension
		return BigInt(low) | (BigInt(high) << 32n);
	}

	readI128(): bigint {
		// Read as unsigned first, then convert to signed
		const unsigned = this.readU128();
		// If sign bit (bit 127) is set, convert to negative
		const signBit = 1n << 127n;
		if ((unsigned & signBit) !== 0n) {
			return unsigned - (1n << 128n);
		}
		return unsigned;
	}

	readF32(): number {
		this.ensureAvailable(4);
		const value = this.view.getFloat32(this.offset, true);
		this.offset += 4;
		return value;
	}

	readF64(): number {
		this.ensureAvailable(8);
		const value = this.view.getFloat64(this.offset, true);
		this.offset += 8;
		return value;
	}

	readBool(): boolean {
		const value = this.readU8();
		if (value > 1) {
			throw new Error(`Invalid boolean value: ${value}`);
		}
		return value === 1;
	}

	// ========== Compound Types ==========

	readBytes(length: number): Uint8Array {
		this.ensureAvailable(length);
		const bytes = this.bytes.slice(this.offset, this.offset + length);
		this.offset += length;
		return bytes;
	}

	readFixedArray(length: number): Uint8Array {
		return this.readBytes(length);
	}

	readVecBytes(): Uint8Array {
		const length = this.readLength();
		return this.readBytes(length);
	}

	readString(): string {
		const bytes = this.readVecBytes();
		return new TextDecoder().decode(bytes);
	}

	readVariant(): number {
		return this.readU32();
	}

	readOption<T>(readValue: () => T): T | null {
		const hasValue = this.readU8();
		if (hasValue === 0) {
			return null;
		}
		if (hasValue !== 1) {
			throw new Error(`Invalid option discriminant: ${hasValue}`);
		}
		return readValue();
	}

	readVec<T>(readElement: () => T): T[] {
		const length = this.readLength();
		const result: T[] = [];
		for (let i = 0; i < length; i++) {
			result.push(readElement());
		}
		return result;
	}

	/**
	 * Read a tuple of fixed size with heterogeneous types
	 */
	readTuple<T extends unknown[]>(readers: { [K in keyof T]: () => T[K] }): T {
		return readers.map((read) => read()) as T;
	}

	readMap<K, V>(readKey: () => K, readValue: () => V): Map<K, V> {
		const length = this.readLength();
		const map = new Map<K, V>();
		for (let i = 0; i < length; i++) {
			const key = readKey();
			const value = readValue();
			map.set(key, value);
		}
		return map;
	}

	// ========== Helpers ==========

	/**
	 * Read length as u64 but validate it's within safe integer range
	 */
	private readLength(): number {
		const length = this.readU64();
		if (length > BigInt(Number.MAX_SAFE_INTEGER)) {
			throw new Error(`Length ${length} exceeds maximum safe integer`);
		}
		const numLength = Number(length);
		// Additional sanity check: length shouldn't exceed remaining bytes
		if (numLength > this.remaining()) {
			throw new Error(
				`Length ${numLength} exceeds remaining bytes ${this.remaining()}`,
			);
		}
		return numLength;
	}

	private ensureAvailable(bytes: number): void {
		if (this.offset + bytes > this.bytes.length) {
			throw new Error(
				`Unexpected end of data: need ${bytes} bytes at offset ${this.offset}, ` +
					`but only ${this.bytes.length - this.offset} available`,
			);
		}
	}
}
